#### Model Solution for Part (b) — 7 Marks

**Complete Server C Program:**

```c
#include <stdio.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>

#define PORT 8080
#define MAX 100

const char* classifyMatrix(int n, int A[MAX][MAX]) {
    int isDiag = 1, isUpper = 1, isLower = 1;

    // Priority 1: Check Diagonal
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i != j && A[i][j] != 0) {
                isDiag = 0; 
                break;
            }
        }
        if (!isDiag) break;
    }
    if (isDiag) return "DIAGONAL";

    // Priority 2: Check Upper Triangular
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (A[i][j] != 0) {
                isUpper = 0; 
                break;
            }
        }
        if (!isUpper) break;
    }
    if (isUpper) return "UPPER TRIANGULAR";

    // Priority 3: Check Lower Triangular
    for (int i = 0; i < n - 1; i++) {
        for (int j = i + 1; j < n; j++) {
            if (A[i][j] != 0) {
                isLower = 0; 
                break;
            }
        }
        if (!isLower) break;
    }
    if (isLower) return "LOWER TRIANGULAR";

    return "NONE";
}

int main() {
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    struct sockaddr_in addr;
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = INADDR_ANY;
    addr.sin_port = htons(PORT);

    bind(server_fd, (struct sockaddr*)&addr, sizeof(addr));
    listen(server_fd, 5);
    printf("Server ready on port %d\n", PORT);

    int client_fd = accept(server_fd, NULL, NULL);
    int n, A[MAX][MAX];

    recv(client_fd, &n, sizeof(n), 0);
    recv(client_fd, A, sizeof(int) * MAX * MAX, 0);

    const char* result = classifyMatrix(n, A);
    send(client_fd, result, strlen(result), 0);
    printf("Sent: %s\n", result);

    close(client_fd);
    close(server_fd);
    return 0;
}
```

