### 3.3 Client Program — `client.c`

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

#define PORT 8080
#define BUF_SIZE 1024

int main(int argc, char *argv[]) {
    int sockfd, n;
    struct sockaddr_in serv_addr;
    char buffer[BUF_SIZE];

    // ---------------- STEP 1: Create TCP socket ----------
    sockfd = socket(AF_INET, SOCK_STREAM, 0);
    if (sockfd < 0) { perror("ERROR opening socket"); exit(1); }

    // ---------------- STEP 2: Set server address --------
    bzero((char *) &serv_addr, sizeof(serv_addr));
    serv_addr.sin_family      = AF_INET;
    serv_addr.sin_port        = htons(PORT);

    // Convert dotted-decimal IP string to binary form
    if (inet_pton(AF_INET, "127.0.0.1", &serv_addr.sin_addr) <= 0) {
        perror("ERROR invalid server IP");
        exit(1);
    }

    // ---------------- STEP 3: Connect to server ----------
    if (connect(sockfd, (struct sockaddr *) &serv_addr, sizeof(serv_addr)) < 0) {
        perror("ERROR connecting");
        exit(1);
    }
    printf("Connected to server.\n");

    // ---------------- STEP 4: Read PID response ----------
    bzero(buffer, BUF_SIZE);
    n = read(sockfd, buffer, BUF_SIZE - 1);
    if (n > 0) {
        buffer[n] = '\0';
        printf("Server reports: %s", buffer);
    }

    // ---------------- STEP 5: Send filename, receive file ----
    printf("Enter filename to request: ");
    bzero(buffer, BUF_SIZE);
    fgets(buffer, BUF_SIZE - 1, stdin);
    buffer[strcspn(buffer, "\n")] = '\0';        // strip newline
    write(sockfd, buffer, strlen(buffer));

    printf("--- File contents from server ---\n");
    while ((n = read(sockfd, buffer, BUF_SIZE - 1)) > 0) {
        buffer[n] = '\0';
        printf("%s", buffer);
    }
    printf("\n--- End of file ---\n");

    close(sockfd);
    return 0;
}
```

